package auth

import (
	"net/http"

	"github.com/harusame0616/ijuku/apps/api/lib/auth"
	"github.com/harusame0616/ijuku/apps/api/lib/response"
)

const (
	pkceVerifierCookie = "pkce_verifier"
	oauthStateCookie   = "oauth_state"
	pkceCookieMaxAge   = 600 // 10 分
)

type OAuthHandler struct {
	supabase   *auth.SupabaseClient
	redirectTo string
	secure     bool
}

func NewOAuthHandler(supabase *auth.SupabaseClient, redirectTo string, secureCookie bool) OAuthHandler {
	return OAuthHandler{supabase: supabase, redirectTo: redirectTo, secure: secureCookie}
}

func (h OAuthHandler) StartOAuth(w http.ResponseWriter, r *http.Request) {
	verifier, err := auth.NewPKCEVerifier()
	if err != nil {
		response.WriteInternalServerErrorResponse(w)
		return
	}
	state, err := auth.NewState()
	if err != nil {
		response.WriteInternalServerErrorResponse(w)
		return
	}

	setShortLivedCookie(w, pkceVerifierCookie, verifier, h.secure)
	setShortLivedCookie(w, oauthStateCookie, state, h.secure)

	authorizeURL := h.supabase.BuildAuthorizeURL("google", h.redirectTo, auth.PKCEChallenge(verifier), state)
	http.Redirect(w, r, authorizeURL, http.StatusFound)
}

func setShortLivedCookie(w http.ResponseWriter, name, value string, secure bool) {
	http.SetCookie(w, &http.Cookie{
		Name:     name,
		Value:    value,
		Path:     "/",
		MaxAge:   pkceCookieMaxAge,
		HttpOnly: true,
		Secure:   secure,
		SameSite: http.SameSiteLaxMode,
	})
}

func clearCookie(w http.ResponseWriter, name string, secure bool) {
	http.SetCookie(w, &http.Cookie{
		Name:     name,
		Value:    "",
		Path:     "/",
		MaxAge:   -1,
		HttpOnly: true,
		Secure:   secure,
		SameSite: http.SameSiteLaxMode,
	})
}

