package auth

import (
	"context"
	"fmt"
	"net/http"
	"time"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/lib/auth"
	"github.com/harusame0616/ijuku/apps/api/lib/response"
)

type userUpserter interface {
	Upsert(ctx context.Context, userID uuid.UUID, nickname string) error
}

type CallbackHandler struct {
	supabase   *auth.SupabaseClient
	users      userUpserter
	successURL string
	secure     bool
}

func NewCallbackHandler(supabase *auth.SupabaseClient, users userUpserter, successURL string, secureCookie bool) CallbackHandler {
	return CallbackHandler{supabase: supabase, users: users, successURL: successURL, secure: secureCookie}
}

func (h CallbackHandler) HandleCallback(w http.ResponseWriter, r *http.Request) {
	code := r.URL.Query().Get("code")
	state := r.URL.Query().Get("state")
	if code == "" {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "code is required")
		return
	}

	stateCookie, err := r.Cookie(oauthStateCookie)
	if err != nil || stateCookie.Value == "" || stateCookie.Value != state {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "state mismatch")
		return
	}

	verifierCookie, err := r.Cookie(pkceVerifierCookie)
	if err != nil || verifierCookie.Value == "" {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "pkce verifier missing")
		return
	}

	tokens, err := h.supabase.ExchangePKCE(r.Context(), code, verifierCookie.Value)
	if err != nil {
		fmt.Printf("pkce exchange: %v\n", err)
		response.WriteInternalServerErrorResponse(w)
		return
	}

	userID, err := uuid.Parse(tokens.User.ID)
	if err != nil {
		response.WriteInternalServerErrorResponse(w)
		return
	}

	nickname := pickNickname(tokens.User.UserMetadata, tokens.User.Email, userID.String())
	if err := h.users.Upsert(r.Context(), userID, nickname); err != nil {
		fmt.Printf("user upsert: %v\n", err)
		response.WriteInternalServerErrorResponse(w)
		return
	}

	clearCookie(w, pkceVerifierCookie, h.secure)
	clearCookie(w, oauthStateCookie, h.secure)
	setAuthCookie(w, tokens.AccessToken, tokens.ExpiresIn, h.secure)

	http.Redirect(w, r, h.successURL, http.StatusFound)
}

func pickNickname(meta map[string]any, email, fallback string) string {
	for _, k := range []string{"name", "full_name", "user_name"} {
		if v, ok := meta[k].(string); ok && v != "" {
			return v
		}
	}
	if email != "" {
		return email
	}
	return fallback
}

func setAuthCookie(w http.ResponseWriter, token string, expiresIn int64, secure bool) {
	maxAge := int(expiresIn)
	if maxAge <= 0 {
		maxAge = int((time.Hour).Seconds())
	}
	http.SetCookie(w, &http.Cookie{
		Name:     auth.AuthCookieName,
		Value:    token,
		Path:     "/",
		MaxAge:   maxAge,
		HttpOnly: true,
		Secure:   secure,
		SameSite: http.SameSiteLaxMode,
	})
}
